sections.example:
fn main() {
    let mut nums = vec![3, 1, 4, 1, 5];
    nums.sort_by(|a, b| b.cmp(a));
    println!("{:?}", nums);  // [5, 4, 3, 1, 1]

    let mut floats = vec![3.1, 1.4, 2.7];
    floats.sort_by(|a, b| a.partial_cmp(b).unwrap());
    println!("{:?}", floats);  // [1.4, 2.7, 3.1]
}

