fn main() {
    let mut words = vec!["banana", "fig", "apple", "kiwi"];
    words.sort_by_key(|w| w.len());
    println!("{:?}", words);  // ["fig", "kiwi", "apple", "banana"]

    let mut nums = vec![-3, 1, -7, 4, -2];
    nums.sort_by_key(|x| x.abs());
    println!("{:?}", nums);  // [1, -2, -3, 4, -7]
}

