sections.example:
fn main() {
    let mut intervals = vec![(3, 5), (1, 4), (1, 2), (2, 6)];
    intervals.sort();
    println!("{:?}", intervals);
    // [(1, 2), (1, 4), (2, 6), (3, 5)]

    // Sort by end time, then start time
    intervals.sort_by_key(|&(_, end)| end);
    println!("{:?}", intervals);
    // [(1, 2), (1, 4), (3, 5), (2, 6)]
}

